import{_ as a,c as o,a1 as r,o as n}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"GUI Tools for Enumeration in Windows","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/3-enumeration/4-Windows-EnumerationTools.md","filePath":"categories/ethical-hacking-labs/3-enumeration/4-Windows-EnumerationTools.md"}'),t={name:"categories/ethical-hacking-labs/3-enumeration/4-Windows-EnumerationTools.md"};function s(i,e,c,l,d,p){return n(),o("div",null,e[0]||(e[0]=[r('<h1 id="gui-tools-for-enumeration-in-windows" tabindex="-1">GUI Tools for Enumeration in Windows <a class="header-anchor" href="#gui-tools-for-enumeration-in-windows" aria-label="Permalink to &quot;GUI Tools for Enumeration in Windows&quot;">​</a></h1><h2 id="global-network-inventory" tabindex="-1">Global Network Inventory <a class="header-anchor" href="#global-network-inventory" aria-label="Permalink to &quot;Global Network Inventory&quot;">​</a></h2><p>Global Network Inventory is used as an audit scanner in zero deployment and agent-free environments. It scans computers by IP range, by domain, and single or multiple computers, as defined by the Global Network Inventory host file. You can enumerate NetBIOS, Users Groups, Users, Software running, BIOS and so on. [Trial/Paid] <a href="http://www.magnetosoft.com/product/global_network_inventory/download" target="_blank" rel="noreferrer">http://www.magnetosoft.com/product/global_network_inventory/download</a></p><h2 id="advanced-ip-scanner" tabindex="-1">Advanced IP Scanner <a class="header-anchor" href="#advanced-ip-scanner" aria-label="Permalink to &quot;Advanced IP Scanner&quot;">​</a></h2><p>Free network scanner to analyse LAN. The program shows all network devices, gives you access to shared folders, provides remote control of computers (via RDP and Radmin), and can even remotely switch computers off. It is easy to use and runs as a portable edition. It should be the first choice for every network admin. [Free] <a href="https://www.advanced-ip-scanner.com/" target="_blank" rel="noreferrer">https://www.advanced-ip-scanner.com/</a></p><h2 id="hyena" tabindex="-1">Hyena <a class="header-anchor" href="#hyena" aria-label="Permalink to &quot;Hyena&quot;">​</a></h2><p>Hyena provides extensive Active Directory (AD) reporting, with built-in tools for customizable queries, filtering, management of object properties, advanced attribute management, and many other AD administration features. [Trial/Paid] <a href="https://systemtools.com/" target="_blank" rel="noreferrer">https://systemtools.com/</a></p><h2 id="superscan" tabindex="-1">SuperScan <a class="header-anchor" href="#superscan" aria-label="Permalink to &quot;SuperScan&quot;">​</a></h2><p>Free Port scanner for Windows. You can use the program to scan IPs, HTTPS, FTP, and more. [Free] <a href="https://superscan.en.softonic.com/" target="_blank" rel="noreferrer">https://superscan.en.softonic.com/</a></p><h2 id="softperfect-networkscanner" tabindex="-1">SoftPerfect NetworkScanner <a class="header-anchor" href="#softperfect-networkscanner" aria-label="Permalink to &quot;SoftPerfect NetworkScanner&quot;">​</a></h2><p>Network scanner can ping computers, scan ports, discover shared folders and so on. [Trial/Paid] <a href="https://www.softperfect.com/products/networkscanner/" target="_blank" rel="noreferrer">https://www.softperfect.com/products/networkscanner/</a></p><h2 id="adexplorer" tabindex="-1">ADExplorer <a class="header-anchor" href="#adexplorer" aria-label="Permalink to &quot;ADExplorer&quot;">​</a></h2><p>Active Directory Explorer (AD Explorer) is an advanced Active Directory (AD) viewer and editor. You can use AD Explorer to easily navigate an AD database, define favorite locations, view object properties and attributes without having to open dialog boxes, edit permissions, view an object&#39;s schema, and execute sophisticated searches that you can save and re-execute.</p><p><a href="https://docs.microsoft.com/en-us/sysinternals/downloads/adexplorer" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/sysinternals/downloads/adexplorer</a></p>',14)]))}const m=a(t,[["render",s]]);export{u as __pageData,m as default};
